import pymongo
from datetime import datetime
from typing import Dict, List, Any

class SalesAnalyzer:
    def __init__(self, db_url: str, db_name: str) -> None:
        self.client = pymongo.MongoClient(db_url)
        self.db = self.client[db_name]

    def get_top_performing_products(self, start_date: str, end_date: str, limit: int = 3) -> Dict[str, List[Dict[str, Any]]]:
        start_dt = datetime.fromisoformat(start_date)
        end_dt = datetime.fromisoformat(end_date)

        pipeline = [
            {
                "$match": {
                    "order_date": {"$gte": start_dt, "$lte": end_dt}
                }
            },
            {
                "$lookup": {
                    "from": "products",
                    "localField": "product_id",
                    "foreignField": "product_id",
                    "as": "product_info"
                }
            },
            {
                "$unwind": {
                    "path": "$product_info",
                    "preserveNullAndEmptyArrays": False
                }
            },
            {
                "$addFields": {
                    "revenue": {"$multiply": ["$quantity", "$product_info.price"]}
                }
            },
            {
                "$group": {
                    "_id": {
                        "category": "$product_info.category",
                        "product_id": "$product_id",
                        "product_name": "$product_info.product_name"
                    },
                    "total_revenue": {"$sum": "$revenue"},
                    "total_quantity": {"$sum": "$quantity"}
                }
            },
            {
                "$sort": {
                    "total_revenue": -1,
                    "total_quantity": -1,
                    "_id.product_id": 1
                }
            },
            {
                "$group": {
                    "_id": "$_id.category",
                    "top_products": {
                        "$push": {
                            "product_id": "$_id.product_id",
                            "product_name": "$_id.product_name",
                            "total_revenue": "$total_revenue",
                            "total_quantity": "$total_quantity"
                        }
                    }
                }
            },
            {
                "$project": {
                    "top_products": {"$slice": ["$top_products", limit]}
                }
            },
            {
                "$sort": {"_id": 1}
            }
        ]

        results = list(self.db.orders.aggregate(pipeline))

        final_result: Dict[str, List[Dict[str, Any]]] = {}
        for doc in results:
            category = doc["_id"]
            products = []
            for p in doc["top_products"]:
                p["total_revenue"] = round(p["total_revenue"], 2)
                products.append(p)
            final_result[category] = products

        return final_result

